// Podbean Broker -- authorize, validate, dispatch.
// BlackCEO's SINGLE Podbean app (client_id/client_secret) lives ONLY inside
// this n8n instance (as the httpBasicAuth credential on the 'Podbean Token'
// node) and never leaves it. The client box holds only the webhook URL + a
// low-privilege shared token (validated HERE) + the Podbean Channel ID.
const EXPECTED = $env.PODBEAN_BROKER_TOKEN || '';
const item = $input.first();
const j = (item && item.json) ? item.json : {};
const body = j.body || {};
const headers = j.headers || {};
const presented = headers['x-podbean-broker-token'] || headers['X-Podbean-Broker-Token'] || body.token || '';

function reject(code, error, extra) {
  return [{ json: { authorized: false, is_mint: false, http_code: code,
    response: Object.assign({ ok: false, error: error }, extra || {}) } }];
}

if (!EXPECTED) return reject(500, 'broker_misconfigured', { detail: 'PODBEAN_BROKER_TOKEN not set in n8n' });
if (!presented || presented !== EXPECTED) return reject(401, 'unauthorized');

const action = (body.action || '').toString();
if (!action) return reject(400, 'missing_action');

const IMPLEMENTED = 'mint_token';
if (action !== IMPLEMENTED) {
  return [{ json: { authorized: true, is_mint: false, http_code: 501,
    response: { ok: false, error: 'not_implemented', action: action,
      note: 'Only mint_token is implemented. It returns a Podbean access token scoped to the requested Channel ID.' } } }];
}

const podcast_id = (body.podcast_id || '').toString().trim();
if (!podcast_id) return reject(400, 'missing_fields', { missing: ['podcast_id'] });

return [{ json: { authorized: true, is_mint: true, http_code: 200, action: action, podcast_id: podcast_id } }];

// Parse the Podbean multiplePodcastsToken response and return a token
// SCOPED to the requested Channel ID. Tolerates both documented shapes:
// { podcast_tokens: [ { podcast_id, access_token, expires_in } ] } or a map
// keyed by podcast id; also accepts a top-level access_token (single-podcast).
const a = $('Authorize & Dispatch').item.json;
const resp = ($input.first() && $input.first().json) ? $input.first().json : {};
const tgt = String(a.podcast_id);
let token = '';
let expires = null;

const list = resp.podcast_tokens;
if (Array.isArray(list)) {
  for (const t of list) {
    if (t && String(t.podcast_id) === tgt) { token = t.access_token || ''; expires = t.expires_in || null; }
  }
}
if (!token) {
  const n = resp[tgt];
  if (n && typeof n === 'object') { token = n.access_token || ''; expires = n.expires_in || null; }
  else if (typeof n === 'string') { token = n; }
}
if (!token && resp.access_token) { token = resp.access_token; expires = resp.expires_in || null; }

if (!token) {
  return [{ json: { ok: false, http_code: 502, action: 'mint_token', via: 'n8n_broker', podcast_id: tgt,
    error: 'token_mint_failed',
    detail: 'Podbean returned no access_token for this Channel ID. Check the BlackCEO Podbean App credential and that the Channel ID belongs to the host account.' } }];
}
return [{ json: { ok: true, http_code: 200, action: 'mint_token', via: 'n8n_broker', podcast_id: tgt, access_token: token, expires_in: expires } }];
